import{_ as a,o as e,c as d,a2 as s}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"플랫폼 관리 기능 이관 — Quickstart (Phase 1)","description":"","frontmatter":{"title":"플랫폼 관리 기능 이관 — Quickstart (Phase 1)","feature_id":"004","created":"2026-05-30 22:30 (KST)","updated":"2026-05-31 15:20 (KST)","date":"2026-05-30T00:00:00.000Z"},"headers":[],"relativePath":"specs/004-platform-admin-migration/quickstart.md","filePath":"specs/004-platform-admin-migration/quickstart.md","lastUpdated":null}'),i={name:"specs/004-platform-admin-migration/quickstart.md"};function o(l,t,r,c,n,p){return e(),d("div",null,[...t[0]||(t[0]=[s(`<h1 id="quickstart-플랫폼-관리-기능-이관" tabindex="-1">Quickstart: 플랫폼 관리 기능 이관 <a class="header-anchor" href="#quickstart-플랫폼-관리-기능-이관" aria-label="Permalink to &quot;Quickstart: 플랫폼 관리 기능 이관&quot;">​</a></h1><p>이관 결과를 로컬에서 기동·검증하는 최소 경로.</p><h2 id="사전-조건" tabindex="-1">사전 조건 <a class="header-anchor" href="#사전-조건" aria-label="Permalink to &quot;사전 조건&quot;">​</a></h2><ul><li>Java 21 LTS, Gradle(래퍼는 <code>setup-gradle</code> 액션/로컬 gradle 사용 — 저장소에 wrapper 부재, 최근 CI 변경 참조).</li><li>런타임: Oracle 21c 접속 정보(운영/개발 DB). 자동 테스트는 H2(Oracle 호환)로 Oracle 없이 수행.</li></ul><h2 id="빌드-테스트-oracle-불필요" tabindex="-1">빌드 &amp; 테스트 (Oracle 불필요) <a class="header-anchor" href="#빌드-테스트-oracle-불필요" aria-label="Permalink to &quot;빌드 &amp; 테스트 (Oracle 불필요)&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 앱 단위/통합 테스트 (H2 Oracle 호환 모드)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gradle :app:test</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 문서 파이프라인 회귀 확인</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cd blog; npx docusaurus build</span></span></code></pre></div><h2 id="앱-기동-oracle-필요" tabindex="-1">앱 기동 (Oracle 필요) <a class="header-anchor" href="#앱-기동-oracle-필요" aria-label="Permalink to &quot;앱 기동 (Oracle 필요)&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Oracle 접속 환경변수 설정 후</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gradle :app:bootRun</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 기본 관리자 시드 계정으로 로그인 → 토큰 발급</span></span></code></pre></div><h2 id="스모크-시나리오" tabindex="-1">스모크 시나리오 <a class="header-anchor" href="#스모크-시나리오" aria-label="Permalink to &quot;스모크 시나리오&quot;">​</a></h2><ol><li><code>POST /api/v1/auth/login</code> (시드 관리자) → Access 토큰 수령, <code>SYS_LOGIN_HISTORY</code> 에 SUCCESS 기록 확인.</li><li><code>GET /api/v1/auth/me</code> → 권한/메뉴 트리 확인.</li><li><code>POST /api/v1/users</code> 로 사용자 생성 → <code>AUDIT_DATA_CHANGE</code> 기록 확인.</li><li>권한 없는 토큰으로 보호 엔드포인트 호출 → <code>403</code> (SC-2).</li><li><code>POST /api/v1/codes/groups</code> → <code>GET /api/v1/codes/groups</code> 반영 확인 (SC-5).</li><li>결재: 다단계 양식 상신 → 단계별 <code>/{id}/action</code> 승인 → 마지막 단계 후 <code>APPROVED</code> (SC-8).</li><li><code>GET /api/v1/audit/login-history?from=…&amp;to=…</code> → 3초 내 결과 (SC-4).</li></ol><h2 id="데모-표면" tabindex="-1">데모(표면) <a class="header-anchor" href="#데모-표면" aria-label="Permalink to &quot;데모(표면)&quot;">​</a></h2><ul><li>앱 기동 후 <code>http://localhost:8080/grid-demo.html</code> → VuGrid 로 <strong>사용자 목록 + 로그인 이력</strong>(R8) 조회 렌더 확인.</li></ul><h2 id="성공기준-매핑" tabindex="-1">성공기준 매핑 <a class="header-anchor" href="#성공기준-매핑" aria-label="Permalink to &quot;성공기준 매핑&quot;">​</a></h2><p>SC-1(22기능 동작)·SC-2(권한거부)·SC-3(감사기록)·SC-4(이력검색 3초)·SC-5(코드/문구 즉시반영)·SC-6(권한신청→반영)·SC-7(범위격리 기동)·SC-8(다단계결재)·SC-9(1년보존).</p><h2 id="검증-결과-2026-05-31-t079" tabindex="-1">검증 결과 (2026-05-31, T079) <a class="header-anchor" href="#검증-결과-2026-05-31-t079" aria-label="Permalink to &quot;검증 결과 (2026-05-31, T079)&quot;">​</a></h2><p>자동 테스트 <strong><code>gradle :app:test</code> 25/25 통과</strong> + <strong><code>docusaurus build</code> 회귀 없음</strong>으로 스모크 시나리오·성공기준을 자동화 검증했다. 스모크 1~7 항목 ↔ 테스트 매핑:</p><table tabindex="0"><thead><tr><th>스모크 / SC</th><th>검증 테스트</th><th>결과</th></tr></thead><tbody><tr><td>1·2 로그인·이력·/me (SC-3)</td><td><code>auth/AuthControllerTest</code>, <code>audit/Us4AuditTest</code></td><td>✅ SUCCESS/FAIL 기록</td></tr><tr><td>3 사용자 생성→데이터변경 (SC-3)</td><td><code>rbac/Us2RbacTest</code>, <code>audit/Us4AuditTest</code></td><td>✅ AUDIT_DATA_CHANGE</td></tr><tr><td>4 권한거부 403 (SC-2)</td><td><code>rbac/Us2RbacTest</code>, 각 US 403 케이스</td><td>✅</td></tr><tr><td>5 코드 즉시반영 (SC-5)</td><td><code>meta/Us3MetadataTest</code> (캐시 evict)</td><td>✅</td></tr><tr><td>6 다단계 결재 (SC-8)</td><td><code>approval/Us5ApprovalTest</code></td><td>✅ APPROVED/REJECTED</td></tr><tr><td>7 이력검색 3초 (SC-4)</td><td><code>audit/AuditPerformanceTest</code> (3,000건)</td><td>✅ 3s 미만</td></tr><tr><td>SC-6 권한신청→반영</td><td><code>permission/Us6PermissionTest</code></td><td>✅</td></tr><tr><td>SC-7 범위격리 기동</td><td><code>PlatformIsolationTest</code></td><td>✅ defect/batch/legacy 빈 0</td></tr><tr><td>SC-9 1년 보존</td><td><code>audit/Us4AuditTest</code> (retention)</td><td>✅</td></tr><tr><td>메일·파일 (SC-1)</td><td><code>mail/Us7MailTest</code>, <code>file/Us7FileTest</code></td><td>✅</td></tr></tbody></table><blockquote><p>데모(표면) 페이지는 Oracle 연동 기동이 필요(자동 테스트는 H2)하므로 수동 확인 항목으로 남긴다: 앱 기동 후 <code>/grid-demo.html</code> 진입 시 시드 관리자 자동 로그인 → 사용자 목록·로그인 이력 2종을 VuGrid 로 렌더(호출 API 는 위 테스트로 검증됨).</p></blockquote>`,18)])])}const k=a(i,[["render",o]]);export{u as __pageData,k as default};
